mapper.select:
SELECT IFNULL(MAX(serial_number), 0)
FROM ai_chat_session_system_prompt
WHERE user_id = #{userId}
  AND session_id = #{sessionId}

SELECT id, session_id, user_id, serial_number, system_prompt, create_time, update_time
FROM ai_chat_session_system_prompt
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
  AND serial_number = 0
LIMIT 1 -- 最多返回1条（避免多条0的情况）

SELECT id, session_id, user_id, serial_number, system_prompt, create_time, update_time
FROM ai_chat_session_system_prompt
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
ORDER BY serial_number

mapper.delete:
DELETE FROM ai_chat_session_system_prompt
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
